const ideas = $('Fetch New Content Ideas').all().map(i => i.json);
const strongPages = $('Find Strong Source Pages').all().map(i => i.json);

// Sort strong pages by clicks DESC
strongPages.sort((a, b) => (b.total_clicks || 0) - (a.total_clicks || 0));

const suggestions = [];

ideas.forEach(idea => {
  // Build a pseudo-slug for the target URL from query
  const slug = (idea.target_query || '')
    .replace(/\s+/g, '-')
    .replace(/[^\w\u0590-\u05FF-]/g, '')
    .substring(0, 60);

  // Determine category from source page URL
  const sourceUrl = idea.source_page_url || '';
  let category = 'guides';
  if (sourceUrl.includes('osek-patur')) category = 'osek-patur';
  else if (sourceUrl.includes('osek-murshe')) category = 'osek-murshe';
  else if (sourceUrl.includes('hevra')) category = 'hevra-bam';
  else if (sourceUrl.includes('compare')) category = 'compare';

  const targetUrl = `https://www.perfect1.co.il/${category}/${slug}`;

  // Pick top 3 strong pages as sources (excluding the idea's own source page)
  const candidatePages = strongPages
    .filter(p => p.page_url !== idea.source_page_url)
    .slice(0, 3);

  // Always include the source page itself as a linker
  candidatePages.unshift({ page_url: idea.source_page_url, total_clicks: 999 });

  candidatePages.slice(0, 3).forEach(sourcePage => {
    suggestions.push({
      content_idea_id: idea.id,
      source_page_url: sourcePage.page_url,
      target_page_url: targetUrl,
      anchor_text: idea.target_query || idea.suggested_article_title,
      reason: `Strong page (${Math.round(sourcePage.total_clicks || 0)} clicks) should link to new article about "${idea.target_query}" for topical authority`
    });
  });
});

return suggestions.map(s => ({ json: s }));
